<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu Desktop</title>
    <style>
        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
            user-select: none;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen, Ubuntu, Cantarell, "Open Sans", "Helvetica Neue", sans-serif;
            overflow: hidden;
            height: 100vh;
            width: 100vw;
        }

        /* Desktop */
        #desktop {
            position: relative;
            width: 100%;
            height: 100%;
            background: linear-gradient(135deg, #2e3440 0%, #3b4252 100%);
            overflow: hidden;
        }

        /* Taskbar */
        #taskbar {
            position: fixed;
            bottom: 0;
            left: 0;
            right: 0;
            height: 48px;
            background-color: rgba(31, 35, 41, 0.9);
            display: flex;
            align-items: center;
            padding: 0 12px;
            z-index: 1000;
            border-top: 1px solid #4c566a;
        }

        .launcher {
            width: 36px;
            height: 36px;
            margin-right: 8px;
            background-color: rgba(255, 255, 255, 0.1);
            border-radius: 4px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.2s ease;
        }

        .launcher:hover {
            background-color: rgba(255, 255, 255, 0.2);
        }

        .launcher-icon {
            width: 24px;
            height: 24px;
            fill: #ffffff;
        }

        /* Windows */
        .window {
            position: absolute;
            background-color: rgba(46, 52, 64, 0.98);
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.5);
            overflow: hidden;
            min-width: 360px;
            min-height: 240px;
            display: flex;
            flex-direction: column;
            border: 1px solid #4c566a;
        }

        .window-header {
            height: 32px;
            background-color: rgba(59, 66, 82, 0.9);
            display: flex;
            align-items: center;
            padding: 0 12px;
            cursor: move;
            border-bottom: 1px solid #4c566a;
        }

        .window-title {
            color: #ffffff;
            font-size: 14px;
            margin-left: 8px;
        }

        .window-controls {
            display: flex;
            align-items: center;
            margin-left: auto;
        }

        .win-close, .win-minimize, .win-maximize {
            width: 12px;
            height: 12px;
            border-radius: 50%;
            cursor: pointer;
            margin-left: 6px;
        }

        .win-close { background-color: #ff5f56; }
        .win-minimize { background-color: #febc2e; }
        .win-maximize { background-color: #27c93f; }

        .window-content {
            flex: 1;
            overflow: auto;
            padding: 16px;
            color: #ffffff;
        }

        /* Files App */
        #files-window {
            top: 80px;
            left: 120px;
            width: 500px;
            height: 400px;
        }

        .path-bar {
            background-color: rgba(31, 35, 41, 0.9);
            padding: 8px 16px;
            border-bottom: 1px solid #4c566a;
            display: flex;
            align-items: center;
        }

        .path-text {
            color: #ffffff;
            font-size: 14px;
            margin-left: 8px;
        }

        .fs-up-btn {
            background-color: rgba(255, 255, 255, 0.1);
            border: none;
            border-radius: 4px;
            padding: 6px 12px;
            color: #ffffff;
            cursor: pointer;
            display: flex;
            align-items: center;
        }

        .fs-up-btn:hover {
            background-color: rgba(255, 255, 255, 0.2);
        }

        .fs-content {
            padding: 16px;
        }

        .fs-item {
            display: flex;
            align-items: center;
            padding: 8px 12px;
            margin-bottom: 4px;
            background-color: rgba(59, 66, 82, 0.7);
            border-radius: 4px;
            cursor: pointer;
            transition: all 0.2s ease;
        }

        .fs-item:hover {
            background-color: rgba(59, 66, 82, 1);
        }

        .fs-icon {
            width: 24px;
            height: 24px;
            margin-right: 12px;
            fill: #ffffff;
        }

        /* Notepad App */
        #notepad-window {
            top: 60px;
            left: 580px;
            width: 600px;
            height: 450px;
        }

        .tabs-container {
            display: flex;
            background-color: rgba(31, 35, 41, 0.9);
            border-bottom: 1px solid #4c566a;
        }

        .tab {
            padding: 8px 16px;
            cursor: pointer;
            color: #b0b8c2;
            font-size: 13px;
            background-color: rgba(59, 66, 82, 0.7);
            border-radius: 4px 4px 0 0;
            margin-right: 4px;
            transition: all 0.2s ease;
        }

        .tab.active {
            color: #ffffff;
            background-color: rgba(46, 52, 64, 1);
            border-bottom: 2px solid #81a1c1;
        }

        .tab:hover:not(.active) {
            background-color: rgba(59, 66, 82, 0.9);
        }

        .new-tab-btn {
            padding: 8px 12px;
            cursor: pointer;
            color: #ffffff;
            font-size: 16px;
            display: flex;
            align-items: center;
            justify-content: center;
            background-color: rgba(59, 66, 82, 0.7);
            border-radius: 4px 4px 0 0;
        }

        .new-tab-btn:hover {
            background-color: rgba(59, 66, 82, 0.9);
        }

        #editor {
            flex: 1;
            width: 100%;
            background-color: #ffffff;
            color: #3b4252;
            border: none;
            resize: none;
            padding: 16px;
            font-family: monospace;
            font-size: 14px;
            line-height: 1.5;
            outline: none;
        }

        /* Icons */
        .folder-icon {
            fill: #fbbf24;
        }

        .file-icon {
            fill: #ffffff;
        }

        .home-icon {
            fill: #81a1c1;
        }

        .files-icon {
            fill: #88c0d0;
        }

        .notepad-icon {
            fill: #b48ead;
        }
    </style>
</head>
<body>
    <div id="desktop">
        <!-- Taskbar -->
        <div id="taskbar">
            <div class="launcher" id="open-files" title="Files">
                <svg class="launcher-icon files-icon" viewBox="0 0 24 24">
                    <path d="M10 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/>
                </svg>
            </div>
            <div class="launcher" id="open-notepad" title="Notepad">
                <svg class="launcher-icon notepad-icon" viewBox="0 0 24 24">
                    <path d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-9V3.5L18.5 9H13z"/>
                </svg>
            </div>
        </div>

        <!-- Files Window -->
        <div id="files-window" class="window">
            <div class="window-header" id="files-drag-handle">
                <div class="window-title">Files</div>
                <div class="window-controls">
                    <div class="win-minimize"></div>
                    <div class="win-maximize"></div>
                    <div class="win-close" data-window="files-window"></div>
                </div>
            </div>
            <div class="path-bar">
                <button id="files-up" class="fs-up-btn">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="#ffffff">
                        <path d="M12 8l-6 6 1.41 1.41L12 10.83l4.59 4.58L18 14z"/>
                    </svg>
                </button>
                <span id="files-path" class="path-text">/</span>
            </div>
            <div class="window-content fs-content" id="files-list">
                <!-- Files will be populated here -->
            </div>
        </div>

        <!-- Notepad Window -->
        <div id="notepad-window" class="window">
            <div class="window-header" id="notepad-drag-handle">
                <div class="window-title">Notepad</div>
                <div class="window-controls">
                    <div class="win-minimize"></div>
                    <div class="win-maximize"></div>
                    <div class="win-close" data-window="notepad-window"></div>
                </div>
            </div>
            <div class="tabs-container" id="tabs">
                <!-- Tabs will be populated here -->
            </div>
            <textarea id="editor" placeholder="Type your notes here..."></textarea>
        </div>
    </div>

    <script>
        // File system data structure
        const fileSystem = {
            "/": ["bin", "etc", "home", "usr", "var"],
            "/bin": ["bash", "ls", "cp", "mv", "rm"],
            "/etc": ["config", "hosts", "passwd"],
            "/home": ["user"],
            "/home/user": ["Documents", "Downloads", "Pictures", "notes.txt"],
            "/home/user/Documents": ["report.odt", "resume.pdf"],
            "/home/user/Downloads": ["ubuntu.iso", "photos.zip"],
            "/home/user/Pictures": ["wallpaper.png", "screenshot.jpg"],
            "/usr": ["bin", "lib", "share"],
            "/var": ["log", "www", "cache"]
        };

        // Files app state
        let currentPath = "/";

        // Notepad state
        let tabs = [];
        let activeTabId = null;
        const STORAGE_KEY = 'ubuntu_notepad_tabs';

        // DOM Elements
        const desktop = document.getElementById('desktop');
        const filesWindow = document.getElementById('files-window');
        const notepadWindow = document.getElementById('notepad-window');
        const filesList = document.getElementById('files-list');
        const filesPath = document.getElementById('files-path');
        const filesUpBtn = document.getElementById('files-up');
        const tabsContainer = document.getElementById('tabs');
        const editor = document.getElementById('editor');

        // Initialize
        document.addEventListener('DOMContentLoaded', () => {
            initFilesApp();
            initNotepad();
            initDraggableWindows();

            // Event listeners for launchers
            document.getElementById('open-files').addEventListener('click', () => showWindow(filesWindow));
            document.getElementById('open-notepad').addEventListener('click', () => showWindow(notepadWindow));
        });

        // Files App Functions
        function initFilesApp() {
            renderFileList();

            filesUpBtn.addEventListener('click', navigateUp);

            // Double click on file items
            filesList.addEventListener('dblclick', (e) => {
                if (e.target.classList.contains('fs-item')) {
                    const name = e.target.dataset.name;
                    handleFsItemClick(name);
                }
            });
        }

        function renderFileList() {
            filesList.innerHTML = '';

            // Show parent directory if not at root
            if (currentPath !== '/') {
                const parentDiv = document.createElement('div');
                parentDiv.className = 'fs-item';
                parentDiv.dataset.name = '..';

                const iconSvg = `<svg class="fs-icon" viewBox="0 0 24 24">
                    <path d="M12 8l-6 6 1.41 1.41L12 10.83l4.59 4.58L18 14z"/>
                </svg>`;

                parentDiv.innerHTML = iconSvg + '<span>.. (Parent Directory)</span>';
                filesList.appendChild(parentDiv);
            }

            // Get files in current directory
            const files = fileSystem[currentPath] || [];

            // Sort: directories first, then alphabetically
            files.sort((a, b) => {
                const aIsDir = currentPath === '/' ? true : (fileSystem[a] !== undefined);
                const bIsDir = fileSystem[b] !== undefined;

                if (aIsDir && !bIsDir) return -1;
                if (!aIsDir && bIsDir) return 1;
                return a.localeCompare(b);
            });

            files.forEach(file => {
                const itemDiv = document.createElement('div');
                itemDiv.className = 'fs-item';
                itemDiv.dataset.name = file;

                // Determine icon based on type
                const isDirectory = fileSystem[file] !== undefined;
                const iconClass = isDirectory ? 'folder-icon' : 'file-icon';
                const label = isDirectory 
                    ? `<svg class="fs-icon folder-icon" viewBox="0 0 24 24">
                        <path d="M10 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/>
                      </svg>`
                    : `<svg class="fs-icon file-icon" viewBox="0 0 24 24">
                        <path d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-9V3.5L18.5 9H13z"/>
                      </svg>`;

                itemDiv.innerHTML = iconClass + '<span>' + file + '</span>';
                filesList.appendChild(itemDiv);
            });

            // Update path display
            filesPath.textContent = currentPath;
        }

        function handleFsItemClick(name) {
            if (name === '..') {
                navigateUp();
                return;
            }

            const newPath = currentPath === '/' ? `/${name}` : `${currentPath}/${name}`;

            if (fileSystem[name] !== undefined) {
                // It's a directory
                currentPath = newPath;
                renderFileList();
            } else {
                // It's a file - open it in notepad for demo purposes
                const content = `This is the contents of ${name}.\n\nYou can edit this in the Notepad app.`;
                createNewTab(name, content);
                showWindow(notepadWindow);
            }
        }

        function navigateUp() {
            if (currentPath === '/') return;

            // Remove last component
            const parts = currentPath.split('/');
            parts.pop();
            currentPath = parts.join('/') || '/';

            renderFileList();
        }

        // Notepad Functions
        function initNotepad() {
            loadTabsFromStorage();

            if (tabs.length === 0) {
                createNewTab('Untitled', '');
            } else {
                activateTab(tabs[0].id);
            }

            // Event listeners
            document.getElementById('new-tab').addEventListener('click', () => {
                createNewTab(`Untitled ${tabs.length}`, '');
            });

            editor.addEventListener('input', updateActiveTabContent);
        }

        function createNewTab(title, content) {
            const tabId = 'tab-' + Date.now();
            const newTab = { id: tabId, title: title, content: content };

            tabs.push(newTab);
            renderTabs();
            activateTab(tabId);
            saveTabsToStorage();
        }

        function renderTabs() {
            tabsContainer.innerHTML = '';

            // Add new tab button
            const newTabBtn = document.createElement('div');
            newTabBtn.id = 'new-tab';
            newTabBtn.className = 'new-tab-btn';
            newTabBtn.innerHTML = '+';
            tabsContainer.appendChild(newTabBtn);

            // Add existing tabs
            tabs.forEach(tab => {
                const tabDiv = document.createElement('div');
                tabDiv.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
                tabDiv.textContent = tab.title;
                tabDiv.dataset.tabId = tab.id;

                tabDiv.addEventListener('click', () => activateTab(tab.id));
                tabsContainer.appendChild(tabDiv);
            });
        }

        function activateTab(tabId) {
            activeTabId = tabId;

            const tabData = tabs.find(t => t.id === tabId);
            if (tabData) {
                editor.value = tabData.content;
            }

            renderTabs();
        }

        function updateActiveTabContent() {
            if (activeTabId) {
                const tabIndex = tabs.findIndex(t => t.id === activeTabId);
                if (tabIndex !== -1) {
                    tabs[tabIndex].content = editor.value;
                    saveTabsToStorage();
                }
            }
        }

        function saveTabsToStorage() {
            localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs));
        }

        function loadTabsFromStorage() {
            const savedTabs = localStorage.getItem(STORAGE_KEY);
            if (savedTabs) {
                try {
                    tabs = JSON.parse(savedTabs);
                    if (tabs.length > 0) {
                        activeTabId = tabs[0].id;
                    }
                } catch (e) {
                    console.error('Error loading tabs:', e);
                    tabs = [];
                    activeTabId = null;
                }
            }
        }

        // Window Management Functions
        function showWindow(windowElement) {
            windowElement.style.display = 'flex';

            // Bring to front by increasing z-index
            const allWindows = document.querySelectorAll('.window');
            let maxZIndex = 100;
            allWindows.forEach(win => {
                const zIndex = parseInt(window.getComputedStyle(win).zIndex);
                if (zIndex > maxZIndex) maxZIndex = zIndex;
            });

            windowElement.style.zIndex = maxZIndex + 1;
        }

        function initDraggableWindows() {
            // Files window
            const filesHeader = document.getElementById('files-drag-handle');
            makeWindowDraggable(filesWindow, filesHeader);

            // Notepad window
            const notepadHeader = document.getElementById('notepad-drag-handle');
            makeWindowDraggable(notepadWindow, notepadHeader);
        }

        function makeWindowDraggable(windowElement, header) {
            let isDragging = false;
            let startX, startY, initialLeft, initialTop;

            header.addEventListener('mousedown', (e) => {
                if (e.target.classList.contains('win-close') || 
                    e.target.classList.contains('win-minimize') ||
                    e.target.classList.contains('win-maximize')) {
                    return; // Don't drag if clicking window controls
                }

                isDragging = true;
                startX = e.clientX;
                startY = e.clientY;

                const rect = windowElement.getBoundingClientRect();
                initialLeft = rect.left;
                initialTop = rect.top;

                // Bring to front
                const allWindows = document.querySelectorAll('.window');
                let maxZIndex = 100;
                allWindows.forEach(win => {
                    const zIndex = parseInt(window.getComputedStyle(win).zIndex);
                    if (zIndex > maxZIndex) maxZIndex = zIndex;
                });

                windowElement.style.zIndex = maxZIndex + 1;
            });

            document.addEventListener('mousemove', (e) => {
                if (!isDragging) return;

                const dx = e.clientX - startX;
                const dy = e.clientY - startY;

                let newLeft = initialLeft + dx;
                let newTop = initialTop + dy;

                // Keep within viewport bounds
                const rect = windowElement.getBoundingClientRect();
                const viewportWidth = window.innerWidth;
                const viewportHeight = window.innerHeight;

                if (newLeft < 0) newLeft = 0;
                if (newTop < 0) newTop = 0;
                if (newLeft + rect.width > viewportWidth) newLeft = viewportWidth - rect.width;
                if (newTop + rect.height > viewportHeight) newTop = viewportHeight - rect.height;

                windowElement.style.left = `${newLeft}px`;
                windowElement.style.top = `${newTop}px`;
            });

            document.addEventListener('mouseup', () => {
                isDragging = false;
            });
        }

        // Close buttons
        document.querySelectorAll('.win-close').forEach(btn => {
            btn.addEventListener('click', (e) => {
                e.stopPropagation();
                const windowId = btn.dataset.window;
                const windowElement = document.getElementById(windowId);

                if (windowElement) {
                    windowElement.style.display = 'none';

                    // If closing notepad, save current state
                    if (windowId === 'notepad-window') {
                        saveTabsToStorage();
                    }
                }
            });
        });

        // Initialize windows to hidden
        filesWindow.style.display = 'none';
        notepadWindow.style.display = 'none';
    </script>
</body>
</html>
